import java.util.*;
import org.apache.commons.cli.*;

public class MyCommandLineParser extends DefaultParser {
  public static final int INDEX_OF_UNRECOGNIZED_TOKEN = 2;

  private ArrayList<Object> unknownTokens = new ArrayList<>();

  @Override
  protected Options getOptions() throws ParseException {
      return super.getOptions();
  }

  @Override
  public CommandLine parse(final String[] args) throws ParseException {
      try {
          CommandLine cmd = super.parse(args);

          for (int i=0 ; i < args.length ; i++) {
              Object o = args[i];

              if (!(o instanceof String)) continue;
              String s = (String) o;

              // If it starts with "-" AND NOT one of the already processed options AND has no associated value AND not "--".
              if (s.startsWith("-") && !cmd.hasOption(s.substring(1).trim()) && s.indexOf(' ') == -1 && !s.equals("--")){
                  this.unknownTokens.add(INDEX_OF_UNRECOGNIZED_TOKEN,args[i]);
                  break;
              }
          }

          return cmd;
      } catch (ParseException pe) {
          throw pe;
      }
  }

  public List<Object> getUnknownTokens() {
      return Collections.unmodifiableList(this.unknownTokens);
  }
}

